+      localAuth=[REDACTED]      reporting: "Enabled",
+      storageUri: "https://examplestorageaccount.blob.core.windows.net",
+    },
+  });
+  console.log(result);
+}
+
+async function main() {
+  await playwrightWorkspacesCreateOrUpdate();
+}
+
+main().catch(console.error);
